#define MDS_ENTITIES_FULL_COUNT (sizeof(MDS_ENTITIES_FULL)/sizeof(MDS_ENTITIES_FULL[0]))

/* Binary search by ASCII byte order. */
static inline const mds_entity_full* mds_entity_full_lookup(const char* name, size_t n) {
    size_t lo = 0, hi = MDS_ENTITIES_FULL_COUNT;
    while (lo < hi) {
        size_t mid = lo + (hi - lo) / 2;
        const mds_entity_full* e = &MDS_ENTITIES_FULL[mid];
        size_t cn = e->nlen < n ? e->nlen : n;
        int c = memcmp(e->name, name, cn);
        if (c == 0) {
            if (e->nlen == n) return e;
            c = e->nlen < n ? -1 : 1;
        }
        if (c < 0) lo = mid + 1; else hi = mid;
    }
    return NULL;
}

